<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header theme-primary">
                    <h4 class="modal-title">{{ $t('Attachments') }}</h4>
                    <button class="close" @click="Close">
                        <em class="fa fa-times"></em>
                    </button>
                </div>
                <div class="float-left mb-0 p-3 col-lg-12">
                    <div class="clearfix"></div>
                    <div class="row mt-3" v-cloak>
                        <template v-if="attachments.length">
                            <div class="col-sm-12 col-md-12 col-lg-3 col-xl-3 float-left" v-for="(doc, index) in attachments">
                                <div class="box border pt-4 text-center">
                                    <div class="img-ico text-center pb-4 file-image doc-icon pt-3" style="min-height:162px;">
                                        <img v-if="doc.attachment_path != null && doc.Debbie_Updated_OCT == 'jpg' || doc.Debbie_Updated_OCT == 'png' || doc.Debbie_Updated_OCT == 'jpeg' || doc.Debbie_Updated_OCT == 'tiff' || doc.Debbie_Updated_OCT == 'bmp' || doc.Debbie_Updated_OCT == 'dib' || doc.Debbie_Updated_OCT == 'ico' || doc.Debbie_Updated_OCT == 'jfif' || doc.Debbie_Updated_OCT == 'jpe' || doc.Debbie_Updated_OCT == 'gif' && doc.Debbie_Updated_OCT == 'tif'" v-bind:src="doc.attachment_path" alt="DefaultImage" />
                                        <span v-else-if="doc.Debbie_Updated_OCT == 'xlsx' || doc.Debbie_Updated_OCT == 'xls'">
                                            <em class="fa fa-file-excel-o mt-4 pt-1" aria-hidden="true"></em>
                                        </span>
                                        <span v-else-if="doc.Debbie_Updated_OCT == 'pdf'">
                                            <em class="fa fa-file-pdf-o text-danger mt-4 pt-1" aria-hidden="true"></em>
                                        </span>
                                        <span v-else-if="doc.Debbie_Updated_OCT == 'docx' || doc.Debbie_Updated_OCT == 'doc'">
                                            <em class="fa fa-file-word-o text-primary mt-4 pt-1" aria-hidden="true"></em>
                                        </span>
                                        <span v-else-if="doc.Debbie_Updated_OCT == 'csv'">
                                            <em class="fa fa-file-text-o text-primary mt-4 pt-1" aria-hidden="true"></em>
                                        </span>
                                        <span v-else>
                                            <em class="fa fa-file text-primary mt-4 pt-1" aria-hidden="true"></em>
                                        </span>
                                    </div>
                                    <hr class="mb-0">
                                    <div class="clearfix"></div>
                                    <div class="row mx-0 my-2">
                                        <div class="col-md-12 text-left text-truncate font-14 mb-2 font-weight"> {{ doc.attachment_name }}</div>
                                        <div class="verticle-action">
                                            <em aria-hidden="true" class="fa fa-ellipsis-v action_icon" @click="openActionIcon($event)"></em>
                                            <span class="action-list-box noneClass" :id="'spnSlider' + index">
                                                <span id="action-list" class="list-actions" style="padding-left: 0px;">
                                                    <a data-toggle="modal" v-on:click="getdownloadfile(doc.attachment_path, '', doc.attachment_name, doc.attachment_desc)" class="actions-onclick edit-list"><i aria-hidden="true" class="fa fa-download"></i><br>Download</a>
                                                    <em aria-hidden="true" class="fa fa-times close close-action"></em>
                                                </span>
                                            </span>
                                        </div>
                                    </div>
                                    <div class="text-muted small mt-2">
                                        <span class="blue-time"> {{ doc.PostedBy }}</span> | {{ formatDateTime(doc.CREATED_AT) }}
                                    </div>
                                </div>
                            </div>
                        </template>
                        <template v-else>
                            <div class="col-12 d-flex justify-content-center align-items-center text-danger">
                                {{ $t('NorecordfoundText') }}
                            </div>
                        </template>
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-danger" @click="Close">
                        {{ $t('Close') }}
                    </button>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataServices from '../../services/DataService';

export default {
    props: {
        ticketId: [String, Number]
    },
    data() {
        return {
            isLoading: false,
            attachments: []
        };
    },
    created: async function () {
        var vm = this;
        await vm.GetAttachmentsByTicketId();
    },
    methods: {
        GetAttachmentsByTicketId: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `TicketId=${vm.ticketId} `;
            await DataServices.GetAttachmentsByTicketId(params).then(async (response) => {
                vm.isLoading = false;
                vm.attachments = [];
                vm.attachments = response.data;
                for (const doc of vm.attachments) {
                    doc.resume_path = await vm.BindSrc(doc.path);
                }
            });
        },
        getdownloadfile: async function (path, type, name, attachement_mime) {
            var vm = this;
            var fileName = name;
            var filePath = path;
            if (filePath == "" && fileName == "" || filePath == null) {
                vm.ShowAlert(vm.$t("FileNotFoundForDownload"), "warning", true, vm.$t("Alert"));
            } else {
                var url = `filePath=${filePath}&fileName=${fileName}`;
                await DataServices.DownloadFile(url).then(async function (response) {
                    if (response.data == "") {
                        vm.ShowAlert(vm.$t("FileNotExist"), "failure", true, vm.$t("Alert"));
                    } else {
                        const byteData = response.data;
                        const fileURL = `data:image/png;base64;base64,${byteData}`;
                        //const fileURL = `data:${((JSON.parse(attachement_mime)).ContentType)};base64,${byteData}`;
                        var fileLink = document.createElement('a');
                        fileLink.href = fileURL;
                        fileLink.setAttribute('download', fileName);
                        document.body.appendChild(fileLink);
                        fileLink.click();
                    }
                })
            }
        },
        BindSrc: async function (filepath) {
            var vm = this;
            var dynamicSrc = '';
            if (filepath) {
                var path = filepath.substring(0, filepath.lastIndexOf("/") + 1);
                var fileName = filepath.substring(filepath.lastIndexOf("/") + 1, filepath.length);
                let Obj = {
                    path: path,
                    fileName: fileName
                };
                var url = JSON.stringify(Obj);
                await DataServices.GetFileSrc(url).then((response) => {
                    if (response.data != '') {
                        dynamicSrc = response.data
                    }
                });
                return dynamicSrc;
            } else {
                return "~/Content/images/DefaultImages/avatar-icon.jpg";
            }
        },
        openActionIcon(e) {
            e.target.nextSibling.removeAttribute('style');
            e.target.nextSibling.setAttribute('style', 'width:240px;');
            e.target.nextSibling.style.display = 'block';
        },
        formatDateTime(datetime) {
            if (!datetime) return '';

            const date = new Date(datetime);

            const month = date.getMonth() + 1;
            const day = date.getDate();
            const year = date.getFullYear();

            let hours = date.getHours();
            const minutes = String(date.getMinutes()).padStart(2, '0');
            const seconds = String(date.getSeconds()).padStart(2, '0');

            const ampm = hours >= 12 ? 'PM' : 'AM';
            hours = hours % 12 || 12;

            return `${month}/${day}/${year} ${hours}:${minutes}:${seconds} ${ampm}`;
        },
        Close() {
            this.$parent.isShowViewAttachment = false;
        }
    }
};
</script>