<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered modal-lg">
            <div class="modal-content">
                <div class="modal-header theme-primary d-flex">
                    <h4 class="modal-title">{{ $t('Description') }}</h4>
                    <button type="button" class="close" @click="Close">
                        <em class="fa fa-times"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <div v-if="description" v-html="description" class="border p-3"></div>
                    <div v-else class="text-center text-danger">
                        {{ $t('NorecordfoundText') }}
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-danger" @click="Close">
                        <em class="fa fa-times pr-2"></em>{{ $t('Close') }}
                    </button>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataServices from "../../services/DataService";

export default {
    props: {
        commentId: {
            type: [String, Number],
            default: null
        }
    },
    data() {
        return {
            isLoading: false,
            description: []
        };
    },
    created: async function () {
      var vm = this;
      await vm.GetDescriptionByTicketId();
    },
    methods: {
        GetDescriptionByTicketId: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `CommentId=${vm.commentId} `;
            await DataServices.GetDescriptionByTicketId(params).then((response) => {
                vm.description = [];
                vm.isLoading = false;
                vm.description = response.data.map(item => item.COMMENT).join('<br/><br/>');
            });
        },
        Close() {
            this.$parent.isShowViewDescription = false;
        }
    }
};
</script>
